import React from "react";
import { Link } from "react-router-dom";
import NavBar from "../Admin/NavBar";
import img from "../images/download.jpg"

export default function Home() {
  return (
    <div>
      
      <NavBar />

      {/* Hero Section */}
      <section
        className="d-flex align-items-center justify-content-center text-center text-dark"
        style={{
          minHeight: "90vh",
          backgroundImage:
            `url(${img})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
        }}
      >
        <div className="bg-transparent p-5 rounded shadow-lg">
          <h1 className="display-4 fw-bold text-primary">Best food for your taste</h1>
          <p className="lead my-3">
            Discover delectable cuisine and unforgettable moments in our
            welcoming, culinary haven.
          </p>
          <div>
            <Link to="/login" className="btn btn-danger btn-lg me-3">
              Book a Table
            </Link>
            <Link to="/menu" className="btn btn-outline-dark btn-lg">
              Explore Menu
            </Link>
          </div>
        </div>
      </section>
    </div>
  );
}
